import datetime as _dt
from dataclasses import replace, fields
from assay_engine.methodology.hypothesis import Hypothesis, HypothesisKind, HypothesisOrigin
from assay_engine.methodology.preregistration import (
    LocalHmacAuthority, lock_hypothesis, verify_preregistration, canonical_hypothesis_digest,
)

UTC = _dt.timezone.utc
auth = LocalHmacAuthority(b"poc-secret-key-0123456789abcdef")

h = Hypothesis(
    hypothesis_id="H1", statement="s", kind=HypothesisKind.UNIT_LEVEL,
    origin=HypothesisOrigin.DISCOVERY, test_name="t", decision_rule="p<=0.05",
    predicted_direction="greater", params={"alpha": 0.05, "k": 3},
)
locked = lock_hypothesis(h, authority=auth, instant=_dt.datetime.now(tz=UTC)-_dt.timedelta(hours=1))

# Digest payload fields vs dataclass fields
DIGEST_FIELDS = {"statement","kind","origin","test_name","decision_rule",
                 "source_claim_id","predicted_direction","params"}
ALL = {f.name for f in fields(Hypothesis)}
print("dataclass fields:", sorted(ALL))
print("NOT in digest:", sorted(ALL - DIGEST_FIELDS))

# Try mutating each decision-bearing field after lock; confirm verify fails (good) for content fields
for fld, newval in [("statement","CHANGED"), ("test_name","other"), ("decision_rule","p<=0.99"),
                    ("predicted_direction","less")]:
    m = replace(locked, **{fld: newval})
    try:
        verify_preregistration(m, authority=auth); print(f"  {fld}: changed -> STILL VERIFIES (BAD)")
    except Exception: print(f"  {fld}: changed -> verify rejects (good)")

# params change after lock
m = replace(locked, params={"alpha": 0.5, "k": 3})  # alpha widened post-lock
try:
    verify_preregistration(m, authority=auth); print("  params: changed -> STILL VERIFIES (BAD)")
except Exception: print("  params: changed -> verify rejects (good)")

# hypothesis_id change after lock
m = replace(locked, hypothesis_id="H_other")
try:
    verify_preregistration(m, authority=auth); print("  hypothesis_id: changed -> STILL VERIFIES (id NOT bound)")
except Exception: print("  hypothesis_id: changed -> verify rejects")
PY
